# JavaScript Function Declaration and Invocation

```javascript
// Function declaration
function sayHello(name) {
    return `Hello, ${name}!`;
}

// Function invocation
const greeting = sayHello('Alice');
console.log(greeting);  // Outputs: Hello, Alice!
```

# JavaScript Function Expressions and Arrow Functions

```javascript
// Function expression
const add = function(x, y) {
    return x + y;
};

// Arrow function
const subtract = (x, y) => x - y;

// Example usage
const sum = add(5, 3);
console.log(sum);  // Outputs: 8
const difference = subtract(5, 3);
console.log(difference);  // Outputs: 2
```
